function initGallery(){document.querySelectorAll(".gallery img").forEach(function(e){e.addEventListener("click",function(){console.log("Imagem clicada:",e.src),openLightbox(e.src)})})}function openLightbox(e){let n=document.createElement("div");n.className="lightbox",n.innerHTML='<img src="'+e+'" alt="Imagem ampliada">',n.addEventListener("click",function(){document.body.removeChild(n)}),document.body.appendChild(n)}function saudar(e){e="Olá, "+e+"! Bem-vindo(a) ao projeto.";return console.log(e),e}document.addEventListener("DOMContentLoaded",function(){console.log("Página carregada com sucesso!"),initGallery(),saudar("visitante")});